const { createClient, ApiKeyStrategy } = require('@wix/sdk');
const { contacts } = require('@wix/contacts/build/cjs/src/contacts-v4-contact.public');

const client = createClient({
  modules: { contacts },
  auth: ApiKeyStrategy({
    apiKey: process.env.WIX_API_KEY,
    siteId: process.env.WIX_SITE_ID,
  }),
});

async function run() {
  const result = await client.contacts.queryContacts().limit(50).find();
  const p1 = result.contacts || [];
  console.log("Page 1 count:", p1.length);
  console.log("Paging metadata:", JSON.stringify(result.pagingMetadata));
  console.log("hasNext:", typeof result.hasNext === "function" ? result.hasNext() : "N/A");

  if (typeof result.hasNext === "function" && result.hasNext()) {
    const page2 = await result.next();
    const p2 = page2.contacts || [];
    console.log("Page 2 count:", p2.length);
    console.log("Page 2 paging:", JSON.stringify(page2.pagingMetadata));
    const p1Ids = new Set(p1.map(c => c._id));
    const uniqueInP2 = p2.filter(c => !p1Ids.has(c._id)).length;
    console.log("Unique new contacts in page 2:", uniqueInP2);
    console.log("Duplicate contacts in page 2:", p2.length - uniqueInP2);
  }
}
run().catch(e => console.error(e.message || e));

