              style={{ width: 18, height: 18, accentColor: BLUE }}
            />
            <span style={{ color: "#333" }}>
              <a href="https://corp.aicu.ai/ja/privacy" target="_blank" rel="noopener" style={{ color: BLUE, textDecoration: "underline" }}>プライバシーポリシー</a>
